import React, {useEffect, useState} from 'react';
import api from '../services/api';

export default function Inventory(){
  const [fish, setFish] = useState([]);
  useEffect(()=>{
    api.get('/fish').then(r=>setFish(r.data)).catch(()=>{});
  },[]);

  return (
    <div>
      <h2>Inventory</h2>
      <table style={{width:'100%'}}>
        <thead><tr><th>Name</th><th>Category</th><th>Price/kg</th><th>Fresh</th></tr></thead>
        <tbody>
          {fish.map(f => (
            <tr key={f.id}><td>{f.name}</td><td>{f.category}</td><td>{f.pricePerKg}</td><td>{f.fresh?'Yes':'No'}</td></tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
